#include <imgui.h>

void DrawMovementExample() {
    static bool panel_visible = true;
    static float panel_x = 780.0f;
    static float marker_x = 0.0f;
    static float marker_direction = 1.0f;

    ImGuiIO& io = ImGui::GetIO();
    const float target_panel_x = panel_visible ? 620.0f : 860.0f;
    panel_x += (target_panel_x - panel_x) * io.DeltaTime * 10.0f;

    marker_x += marker_direction * io.DeltaTime * 140.0f;
    if (marker_x > 220.0f) {
        marker_x = 220.0f;
        marker_direction = -1.0f;
    }
    if (marker_x < 0.0f) {
        marker_x = 0.0f;
        marker_direction = 1.0f;
    }

    ImGui::Begin("Motion Controls");
    if (ImGui::Button(panel_visible ? "Hide Panel" : "Show Panel")) {
        panel_visible = !panel_visible;
    }
    ImGui::Text("marker_x: %.1f", marker_x);
    ImGui::Text("panel_x: %.1f", panel_x);

    ImVec2 track_min = ImGui::GetCursorScreenPos();
    ImGui::InvisibleButton("motion_track", ImVec2(260.0f, 36.0f));
    ImGui::SetCursorScreenPos(ImVec2(track_min.x + marker_x, track_min.y));
    ImGui::Button("##moving_marker", ImVec2(28.0f, 36.0f));
    ImGui::End();

    ImGui::SetNextWindowPos(ImVec2(panel_x, 90.0f));
    ImGui::SetNextWindowSize(ImVec2(220.0f, 180.0f));
    ImGui::Begin("Sliding Panel", nullptr, ImGuiWindowFlags_NoResize);
    ImGui::Text("هذه اللوحة تنزلق بين موضعين.");
    ImGui::Text("الحالة محفوظة في panel_x.");
    ImGui::End();
}

