#include <imgui.h>
#include <cmath>

void DrawClockWidgetExample() {
    ImGui::Begin("Clock Widget");
    ImGui::Text("ساعة تناظرية ورقمية داخل الواجهة.");

    ImVec2 canvas_min = ImGui::GetCursorScreenPos();
    ImVec2 canvas_size(260.0f, 220.0f);
    ImGui::InvisibleButton("clock_canvas", canvas_size);
    ImDrawList* draw_list = ImGui::GetWindowDrawList();

    ImVec2 center(canvas_min.x + 130.0f, canvas_min.y + 96.0f);
    const float radius = 68.0f;
    const float t = (float)ImGui::GetTime();
    const float seconds = fmodf(t, 60.0f);
    const float minutes = fmodf(t / 60.0f, 60.0f);
    const float hours = fmodf(t / 3600.0f, 12.0f);

    draw_list->AddRectFilled(canvas_min, ImVec2(canvas_min.x + canvas_size.x, canvas_min.y + canvas_size.y), IM_COL32(18, 27, 39, 255), 14.0f);
    draw_list->AddCircle(center, radius, IM_COL32(86, 120, 160, 255), 0, 3.0f);

    for (int i = 0; i < 12; ++i) {
        const float angle = -IM_PI / 2.0f + (IM_PI * 2.0f * i) / 12.0f;
        ImVec2 p1(center.x + cosf(angle) * (radius - 8.0f), center.y + sinf(angle) * (radius - 8.0f));
        ImVec2 p2(center.x + cosf(angle) * radius, center.y + sinf(angle) * radius);
        draw_list->AddLine(p1, p2, IM_COL32(225, 233, 244, 255), 2.0f);
    }

    const float second_angle = -IM_PI / 2.0f + (seconds / 60.0f) * IM_PI * 2.0f;
    const float minute_angle = -IM_PI / 2.0f + (minutes / 60.0f) * IM_PI * 2.0f;
    const float hour_angle = -IM_PI / 2.0f + (hours / 12.0f) * IM_PI * 2.0f;

    ImVec2 second_hand(center.x + cosf(second_angle) * (radius - 12.0f), center.y + sinf(second_angle) * (radius - 12.0f));
    ImVec2 minute_hand(center.x + cosf(minute_angle) * (radius - 20.0f), center.y + sinf(minute_angle) * (radius - 20.0f));
    ImVec2 hour_hand(center.x + cosf(hour_angle) * (radius - 30.0f), center.y + sinf(hour_angle) * (radius - 30.0f));

    draw_list->AddLine(center, hour_hand, IM_COL32(255, 214, 116, 255), 5.0f);
    draw_list->AddLine(center, minute_hand, IM_COL32(116, 191, 255, 255), 4.0f);
    draw_list->AddLine(center, second_hand, IM_COL32(255, 116, 116, 255), 2.0f);
    draw_list->AddCircleFilled(center, 5.0f, IM_COL32(243, 247, 252, 255));

    ImGui::Text("h=%.1f  m=%.1f  s=%.1f", hours, minutes, seconds);
    ImGui::End();
}

