#include <imgui.h>
#include <cmath>

struct WirePoint3 {
    float x, y, z;
};

void DrawWireframePreviewExample() {
    static float angle = 0.0f;
    angle += ImGui::GetIO().DeltaTime * 1.2f;

    static const WirePoint3 cube[8] = {
        {-1.0f, -1.0f, -1.0f}, { 1.0f, -1.0f, -1.0f},
        { 1.0f,  1.0f, -1.0f}, {-1.0f,  1.0f, -1.0f},
        {-1.0f, -1.0f,  1.0f}, { 1.0f, -1.0f,  1.0f},
        { 1.0f,  1.0f,  1.0f}, {-1.0f,  1.0f,  1.0f}
    };
    static const int edges[12][2] = {
        {0,1},{1,2},{2,3},{3,0},
        {4,5},{5,6},{6,7},{7,4},
        {0,4},{1,5},{2,6},{3,7}
    };

    ImGui::Begin("Wireframe 3D");
    ImGui::Text("معاينة 3D مبسطة داخل نافذة أدوات.");

    ImVec2 canvas_min = ImGui::GetCursorScreenPos();
    ImVec2 canvas_size(360.0f, 250.0f);
    ImVec2 center(canvas_min.x + 180.0f, canvas_min.y + 126.0f);
    ImGui::InvisibleButton("wire_canvas", canvas_size);
    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    draw_list->AddRectFilled(canvas_min, ImVec2(canvas_min.x + canvas_size.x, canvas_min.y + canvas_size.y), IM_COL32(16, 23, 34, 255), 14.0f);

    ImVec2 projected[8];
    for (int i = 0; i < 8; ++i) {
        WirePoint3 p = cube[i];
        float rx = p.x * cosf(angle) - p.z * sinf(angle);
        float rz = p.x * sinf(angle) + p.z * cosf(angle);
        float ry = p.y * cosf(angle * 0.6f) - rz * sinf(angle * 0.6f);
        float depth = 3.8f + rz;
        float perspective = 74.0f / depth;
        projected[i] = ImVec2(center.x + rx * perspective * 34.0f, center.y + ry * perspective * 34.0f);
    }

    for (int i = 0; i < 12; ++i) {
        draw_list->AddLine(projected[edges[i][0]], projected[edges[i][1]], IM_COL32(105, 181, 255, 255), 2.2f);
    }

    ImGui::Text("Rotation: %.2f", angle);
    ImGui::Text("النتيجة: مجسم سلكي متحرك داخل نافذة ImGui.");
    ImGui::End();
}
